1	import { run, BASE_PREMIUMS } from "./claim-office.js";
2	
3	type Item = { type: string };
4	type Damage = { itemType: string; amount: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: { damages: Damage[] } };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { steps: Step[] };
9	
10	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
11	
12	const failWith = (message: string): never => {
13	  console.error(message);
14	  process.exit(1);
15	};
16	
17	const validateQuote = (step: QuoteStep): void => {
18	  for (const item of step.items) {
19	    if (!isKnownItemType(item.type)) {
20	      failWith(`unknown item type: ${item.type}`);
21	    }
22	  }
23	};
24	
25	const countByType = <T extends { [k: string]: unknown }>(items: T[], key: keyof T): Map<string, number> => {
26	  const counts = new Map<string, number>();
27	  for (const item of items) {
28	    const k = item[key] as string;
29	    counts.set(k, (counts.get(k) ?? 0) + 1);
30	  }
31	  return counts;
32	};
33	
34	const validateDamage = (damage: Damage): void => {
35	  if (damage.amount < 0) {
36	    failWith(`negative damage amount: ${damage.amount}`);
37	  }
38	};
39	
40	const validateClaim = (step: ClaimStep, scenario: Scenario): void => {
41	  const policyStep = scenario.steps[step.policy] as QuoteStep;
42	  const policyCounts = countByType(policyStep.items, "type");
43	  const damageCounts = countByType(step.incident.damages, "itemType");
44	  for (const damage of step.incident.damages) {
45	    validateDamage(damage);
46	  }
47	  for (const [type, count] of damageCounts) {
48	    if (count > (policyCounts.get(type) ?? 0)) {
49	      failWith(`more damages of type ${type} than policy covers`);
50	    }
51	  }
52	};
53	
54	const validateScenario = (scenario: Scenario): void => {
55	  for (const step of scenario.steps) {
56	    if (step.op === "quote") validateQuote(step);
57	    else if (step.op === "claim") validateClaim(step, scenario);
58	  }
59	};
60	
61	const readStdin = async (): Promise<string> => {
62	  const chunks: Buffer[] = [];
63	  for await (const chunk of process.stdin) {
64	    chunks.push(chunk as Buffer);
65	  }
66	  return Buffer.concat(chunks).toString("utf8");
67	};
68	
69	const main = async (): Promise<void> => {
70	  const scenario = JSON.parse(await readStdin()) as Scenario;
71	  validateScenario(scenario);
72	  console.log(JSON.stringify(run(scenario)));
73	};
74	
75	main();
